3159 Instruction *InstCombinerImpl::visitUnconditionalBranchInst(BranchInst &BI) {
3160   assert(BI.isUnconditional() && "Only for unconditional branches.");
3161 
3162   // If this store is the second-to-last instruction in the basic block
3163   // (excluding debug info and bitcasts of pointers) and if the block ends with
3164   // an unconditional branch, try to move the store to the successor block.
3165 
3166   auto GetLastSinkableStore = [](BasicBlock::iterator BBI) {
3167     auto IsNoopInstrForStoreMerging = [](BasicBlock::iterator BBI) {
3168       return BBI->isDebugOrPseudoInst() ||
3169              (isa<BitCastInst>(BBI) && BBI->getType()->isPointerTy());
3170     };
3171 
3172     BasicBlock::iterator FirstInstr = BBI->getParent()->begin();
3173     do {
3174       if (BBI != FirstInstr)
3175         --BBI;
3176     } while (BBI != FirstInstr && IsNoopInstrForStoreMerging(BBI));
3177 
3178     return dyn_cast<StoreInst>(BBI);
3179   };
3180 
3181   if (StoreInst *SI = GetLastSinkableStore(BasicBlock::iterator(BI)))
3182     if (mergeStoreIntoSuccessor(*SI))
3183       return &BI;
3184 
3185   return nullptr;
3186 }
