1881 /// For floating-point classes that resolve to a single bit pattern, return that
1882 /// value.
1883 static Constant *getFPClassConstant(Type *Ty, FPClassTest Mask) {
1884   switch (Mask) {
1885   case fcPosZero:
1886     return ConstantFP::getZero(Ty);
1887   case fcNegZero:
1888     return ConstantFP::getZero(Ty, true);
1889   case fcPosInf:
1890     return ConstantFP::getInfinity(Ty);
1891   case fcNegInf:
1892     return ConstantFP::getInfinity(Ty, true);
1893   case fcNone:
1894     return PoisonValue::get(Ty);
1895   default:
1896     return nullptr;
1897   }
1898 }
